class Solution {
    public List<Integer> grayCode(int n) {
        List<Integer> result = new ArrayList<>();
        int start = 1 << n - 1;
        int end = (1 << n) - 1;

        for (int i = start; i <= end; i = i ^ (i >> 1)) {
            result.add(i);
        }

        return result;
    }
}
```

